export default function TechStack() {
  return (
    <div className="py-24 border-t border-white/[0.08] bg-[#08090a]">
      <div className="max-w-7xl mx-auto px-6">
        <p className="text-center text-sm font-mono text-zinc-500 mb-12 uppercase tracking-widest">
          Powering Mission-Critical Infrastructure
        </p>

        <div className="relative w-full">
          {/* Mobile: Vertical Grid */}
          <div className="grid grid-cols-3 gap-x-8 gap-y-12 md:hidden place-items-center pb-12">
            {techs.map((tech, i) => (
              <div
                key={`mobile-${i}`}
                className="group flex flex-col items-center gap-3 grayscale opacity-60 hover:grayscale-0 hover:opacity-100 transition-all duration-300"
              >
                {tech.icon ? (
                  <div className="w-8 h-8 flex items-center justify-center">
                    {tech.icon}
                  </div>
                ) : (
                  <img
                    src={`https://cdn.simpleicons.org/${tech.slug}/ffffff`}
                    alt={tech.name}
                    className="w-8 h-8 object-contain"
                    loading="lazy"
                  />
                )}
                <span className="text-[10px] text-zinc-500 font-mono uppercase tracking-wider group-hover:text-zinc-300">
                  {tech.name}
                </span>
              </div>
            ))}
          </div>

          {/* Desktop: Horizontal Marquee */}
          <div className="hidden md:flex w-full overflow-hidden max-w-full mask-linear-fade">
            <div className="flex w-full">
              <div
                className="flex min-w-full shrink-0 animate-marquee items-center justify-around gap-12 sm:gap-24"
                style={
                  { "--duration": "40s", "--gap": "0" } as React.CSSProperties
                }
              >
                {techs.map((tech, i) => (
                  <div
                    key={i}
                    className="group flex flex-col items-center gap-4 grayscale opacity-40 hover:grayscale-0 hover:opacity-100 transition-all duration-500 hover:scale-110 cursor-pointer"
                  >
                    {tech.icon ? (
                      <div className="w-10 h-10 sm:w-12 sm:h-12 flex items-center justify-center">
                        {tech.icon}
                      </div>
                    ) : (
                      <img
                        src={`https://cdn.simpleicons.org/${tech.slug}/ffffff`}
                        alt={tech.name}
                        className="w-10 h-10 sm:w-12 sm:h-12 object-contain"
                        loading="lazy"
                      />
                    )}
                  </div>
                ))}
              </div>
              <div
                className="flex min-w-full shrink-0 animate-marquee items-center justify-around gap-12 sm:gap-24 ml-12 sm:ml-24"
                style={
                  { "--duration": "40s", "--gap": "0" } as React.CSSProperties
                }
              >
                {techs.map((tech, i) => (
                  <div
                    key={`dup-${i}`}
                    className="group flex flex-col items-center gap-4 grayscale opacity-40 hover:grayscale-0 hover:opacity-100 transition-all duration-500 hover:scale-110 cursor-pointer"
                  >
                    {tech.icon ? (
                      <div className="w-10 h-10 sm:w-12 sm:h-12 flex items-center justify-center">
                        {tech.icon}
                      </div>
                    ) : (
                      <img
                        src={`https://cdn.simpleicons.org/${tech.slug}/ffffff`}
                        alt={tech.name}
                        className="w-10 h-10 sm:w-12 sm:h-12 object-contain"
                        loading="lazy"
                      />
                    )}
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
